class Equip {
    hp = 0
    atk = 0
    def = 0
    hpp = 0
    atkp = 0
    defp = 0
    em = 0
    er = 0
    cr = 0
    cd = 0
}

class Stat {
    lv = 90
    baseAtk = 0
    baseDef = 0
    baseHp = 0
    atk = 0
    def = 0
    hp = 0
    atkp = 0
    hpp = 0
    defp = 0
    em = 0
    cr = 0.05
    cd = 0.5
    bonus = 0
    skill = 1
    base = 'atk' // 'atk', 'def', 'hp'
    crit = 'avg' // 'min', 'avg', 'max'
    reac = '' // '', 'p-h', 'h-p', 'p-c', 'c-p'
    enmLv = 100
    enmRes = 0.1
    enmDefRdc = 0

    /**
     * 
     * @param {Object} obj 
     */
    constructor(obj) {
        for (let key in obj) {
            this[key] = obj[key]
        }
    }

    copy() {
        let s = new Stat()
        for (let key of Object.keys(s)) {
            s[key] = this[key]
        }
        return s
    }

    /**
     * 
     * @param {Equip} e 
     */
    equip(e) {
        let s = this.copy()
        for (let key of Object.keys(e)) {
            if (key != 'er') {
                s[key] += e[key]
            }
        }
        return s
    }
}


export { Stat, Equip }