/**
 * 
 * @param {array} arr 
 * @param {number} i 
 * @param {number} j 
 */
function swap(arr, i, j) {
    let t = arr[i]
    arr[i] = arr[j]
    arr[j] = t
}

/**
 * 
 * @param {Object} obj 
 */
function copy(obj) {
    return JSON.parse(JSON.stringify(obj))
}

/**
 * 
 * @param {number|array} arr 
 * @param {number} [n] 
 * @param {array} [p] 
 */
function choice(arr, n, p) {
    if (typeof arr === 'number') {
        return Math.floor(Math.random() * arr)
    } else if (p) {
        /** @type {array} */
        let ret = copy(arr)
        p = copy(p)
        let sum = 0;
        for (let w of p) {
            sum += w
        }
        for (let i = 0; i < n; ++i) {
            let r = Math.random() * sum
            let acc = 0
            for (let j = i; j < ret.length; ++j) {
                acc += p[j]
                if (r < acc) {
                    sum -= p[j]
                    swap(ret, i, j)
                    swap(p, i, j)
                    break
                }
            }
        }
        return ret.slice(0, n)
    } else {
        let i = Math.floor(Math.random() * arr.length)
        return arr[i]
    }
}

export { copy, choice }