<script>
import { Characters } from "../ys/characters";
import { learn, normalize } from "../ys/learn";
import { Stat } from "../ys/stat";
import { simulate } from "../ys/simulate";
import { MainAffixStat } from "../ys/artifact";
import { damage } from "../ys/damage";
import Chart from "chart.js/auto";

/**
 * @param {number|string} n
 */
function num(n) {
    if (typeof n === "number") {
        return n;
    } else {
        return parseFloat(n);
    }
}

const chs = {
    atk: "攻击力",
    def: "防御力",
    hp: "生命值",
    atkp: "攻击力%",
    defp: "防御力%",
    hpp: "生命值%",
    cr: "暴击率",
    cd: "暴击伤害",
    em: "精通",
    er: "充能",
};

let chart = undefined;

export default {
    data: () => ({
        char: {
            key: "Amber",
            weap: 0,
            skill: 100,
            type: "atk",
            crit: "avg",
            reac: "",
        },
        arti: {
            sands: "atkp",
            goblet: "bonus",
            circlet: "cr",
        },
        enmy: {
            show: false,
            lv: 100,
            res: 10,
        },
        buff: {
            show: false,
            atk: 0,
            atkp: 0,
            hp: 0,
            hpp: 0,
            def: 0,
            defp: 0,
            cr: 0,
            cd: 0,
            em: 0,
            er: 0,
            bonus: 0,
            resRdc: 0,
        },
        cura: {
            show: false,
            hp: 0,
            def: 0,
            atk: 0,
            cr: 0,
            cd: 0,
            em: 0,
            er: 0,
        },
        simu: {
            show: false,
            size: 10000,
            resin: 20000,
            times: 50,
        },
        weights: "",
        weightsCode: "",
        show: false,
    }),
    computed: {
        stat() {
            let character = Characters[this.char.key];
            let stat = new Stat(character);
            stat.baseAtk += num(this.char.weap);
            stat.skill = num(this.char.skill) / 100;
            stat.base = this.char.type;
            stat.crit = this.char.crit;
            switch (this.char.reac) {
                case "two":
                    stat.reac = "p-c";
                    break;
                case "one":
                    stat.reac = "c-p";
                    break;
                default:
                    stat.reac = "";
            }
            // artifact
            stat.hp += 4780;
            stat.atk += 311;
            let key = this.arti.sands;
            stat[key] += MainAffixStat["sands"][key]["v"];
            if (this.arti.goblet == "bonus") {
                stat.bonus += this.char.reac == "physical" ? 0.583 : 0.466;
            } else {
                key = this.arti.goblet;
                stat[key] += MainAffixStat["goblet"][key]["v"];
            }
            key = this.arti.circlet;
            stat[key] += MainAffixStat["circlet"][key]["v"];
            // enemy
            stat.enmLv = num(this.enmy.lv);
            stat.enmRes = num(this.enmy.res) / 100;
            // buff
            stat.atk += num(this.buff.atk);
            stat.def += num(this.buff.def);
            stat.hp += num(this.buff.hp);
            stat.atkp += num(this.buff.atkp) / 100;
            stat.defp += num(this.buff.defp) / 100;
            stat.hpp += num(this.buff.hpp) / 100;
            stat.cr += num(this.buff.cr) / 100;
            stat.cd += num(this.buff.cd) / 100;
            stat.em += num(this.buff.em);
            stat.bonus += num(this.buff.bonus) / 100;
            stat.enmDefRdc += num(this.buff.resRdc) / 100;
            return stat;
        },
        curDmg() {
            let stat = this.stat.copy();
            stat.atk += num(this.cura.atk);
            stat.hp += num(this.cura.hp);
            stat.def += num(this.cura.def);
            stat.cr += num(this.cura.cr) / 100;
            stat.cd += num(this.cura.cd) / 100;
            stat.em += num(this.cura.em);
            return damage(stat);
        },
    },
    methods: {
        grad() {
            let weights = learn(this.stat, this.simu.size);
            let nw = normalize(weights);
            this.weightsCode = JSON.stringify(nw);
            this.weights = "";
            for (let key in chs) {
                if (nw[key] > 0) {
                    this.weights += `<tr><td>${chs[key]}</td><td>${nw[key]}</td></tr>`;
                }
            }
            let { clb, avg, cub } = simulate(
                this.stat,
                {
                    flower: "hp",
                    plume: "atk",
                    sands: this.arti.sands,
                    goblet:
                        this.arti.goblet === "bonus"
                            ? "pyro"
                            : this.arti.goblet,
                    circlet: this.arti.circlet,
                },
                weights,
                Math.floor((this.simu.resin / 20) * 1.1),
                this.simu.times
            );
            let labels = [],
                cur = [];
            for (let i = 0; i < avg.length; ++i) {
                labels.push(((i * 20) / 1.1).toFixed(0));
                cur.push(this.curDmg);
            }
            if (chart) {
                chart.destroy();
            }
            let ctx = document.getElementById("myChart");
            // @ts-ignore
            chart = new Chart(ctx, {
                type: "line",
                data: {
                    labels,
                    datasets: [
                        {
                            label: "95%置信区间下界",
                            data: clb,
                            borderWidth: 1,
                            fill: false,
                        },
                        {
                            label: "平均伤害",
                            data: avg,
                            borderWidth: 1,
                            borderColor: "rgb(30, 144, 255)",
                            fill: false,
                        },
                        {
                            label: "95%置信区间上界",
                            data: cub,
                            borderWidth: 1,
                            fill: "-2",
                        },
                        {
                            label: "当前伤害",
                            data: cur,
                            borderColor: "rgb(255, 20, 147)",
                            borderWidth: 1,
                        },
                    ],
                },
                options: {
                    elements: {
                        point: {
                            radius: 0,
                        },
                    },
                    scales: {
                        x: {
                            title: {
                                display: true,
                                text: "体力",
                            },
                        },
                        y: {
                            title: {
                                display: true,
                                text: "伤害",
                            },
                        },
                    },
                    maintainAspectRatio: false,
                },
            });
            this.show = true;
        },
    },
};
</script>

