import { Stat } from "./stat"

/**
 * 
 * @param {Stat} stat 
 * @returns 
 */
function damage(stat) {
    let BASE = stat.base == 'def' ? stat.baseDef * (1 + stat.defp) + stat.def
        : stat.base == 'hp' ? stat.baseHp * (1 + stat.hpp) + stat.hp
            : stat.base == 'atk' ? stat.baseAtk * (1 + stat.atkp) + stat.atk
                : 0
    let SKILL = stat.skill
    let BONUS = 1 + stat.bonus
    let DEF = (stat.lv + 100) / (stat.lv + 100 + (stat.enmLv + 100) * (1 - stat.enmDefRdc))
    let RES = stat.enmRes < 0 ? 1 - stat.enmRes / 2
        : stat.enmRes < 0.75 ? 1 - stat.enmRes
            : 1 / (1 + 4 * stat.enmRes)
    let CRIT = stat.crit == 'min' ? 1
        : stat.crit == 'max' ? 1 + stat.cd
            : stat.crit == 'avg' ? 1 + stat.cr * stat.cd
                : 0
    let multi = 1 + 2.78 * stat.em / (stat.em + 1400)
    let VM = stat.reac == '' ? 1
        : stat.reac == 'p-h' ? 1.5 * multi
            : stat.reac == 'h-p' ? 2 * multi
                : stat.reac == 'p-c' ? 2 * multi
                    : stat.reac == 'c-p' ? 1.5 * multi
                        : 0
    return BASE * SKILL * BONUS * DEF * RES * CRIT * VM
}

export { damage }