import MLR from "ml-regression-multivariate-linear"

import { Stat, Equip } from "./stat"
import { damage } from "./damage"
import { randArtifact, MinorAffixStat, Artifact, MinorAffixes } from "./artifact"

function randArtifactSet() {
    let ret = []
    for (let i = 0; i < 5; ++i) {
        let A = randArtifact()
        ret.push(A)
    }
    return ret
}

/**
 * 
 * @param {Artifact[]} artifacts 
 * @returns 
 */
function artifacts2equip(artifacts) {
    let equip = new Equip()
    for (let A of artifacts) {
        for (let a of A.minorAffixes) {
            equip[a.key] += a.value
        }
    }
    return equip
}

/**
 * 
 * @param {Equip} e 
 */
function equip2input(e) {
    let x = []
    for (let key in MinorAffixStat) {
        x.push(e[key] / MinorAffixStat[key]['v'])
    }
    return x
}

/**
 * 
 * @param {number[]} weights 
 */
function normalize(weights) {
    let ret = {}
    let max = 0
    for (let i = 0; i < MinorAffixes.length; ++i) {
        let key = MinorAffixes[i]
        let value = weights[i] > 0 ? weights[i] : 0
        ret[key] = value
        max = value > max ? value : max
    }
    if (max > 0) {
        for (let key in ret) {
            ret[key] /= max
            ret[key] = Math.floor(ret[key] * 100 + 0.5) / 100
        }
    }
    return ret
}

/**
 * 
 * @param {Stat} stat 
 * @param {number} N Size of training set
 */
function learn(stat, N) {
    let X = [], y = []
    for (let _ = 0; _ < N; ++_) {
        let S = randArtifactSet()
        let e = artifacts2equip(S)
        let s = stat.equip(e)
        let d = damage(s)
        let x = equip2input(e)
        X.push(x)
        y.push([d])
    }
    const model = new MLR(X, y)
    let weights = []
    for (let i = 0; i < model.weights.length - 1; ++i) {
        weights.push(model.weights[i][0])
    }
    return weights
}

export { artifacts2equip, equip2input }
export { learn, normalize }