const ArtifactTypes = ['flower', 'plume', 'sands', 'goblet', 'circlet']


class Affix {
    key = ''
    value = 0

    /**
     * @param {string} [key]
     */
    constructor(key) {
        if (key) {
            this.key = key
            this.enhance()
        }
    }

    enhance() {
        let l = choice(4) * 0.1 + 0.7
        let m = MinorAffixStat[this.key]['v']
        this.value += m * l
    }
}

class Artifact {
    set = ''
    type = ''
    rarity = 0
    level = 0
    mainAffix = new Affix()
    /**
     * @type {Affix[]}
     */
    minorAffixes = []
    data = {}
}

function randArtifact() {
    let A = new Artifact()
    let draw = choice(MinorAffixes, 4, MinorAffixDistr)
    for (let key of draw) {
        let a = new Affix(key)
        A.minorAffixes.push(a)
    }
    let N = choice(2) + 4
    for (let i = 0; i < N; ++i) {
        let j = choice(4)
        A.minorAffixes[j].enhance()
    }
    return A
}

export { Affix, Artifact, MinorAffixStat, MinorAffixes, randArtifact, MainAffixStat, ArtifactTypes }