import { Stat, Equip } from "./stat"
import { Artifact, randArtifact, ArtifactTypes, MainAffixStat } from "./artifact"
import { artifacts2equip, equip2input } from "./learn"
import { choice } from "./utils"
import { damage } from "./damage"

/**
 * 
 * @param {Artifact} A 
 * @param {number[]} weights 
 */
function score(A, weights) {
    let e = artifacts2equip([A])
    let x = equip2input(e)
    let s = 0
    for (let i = 0; i < x.length; ++i) {
        s += x[i] * weights[i]
    }
    return s
}

/**
 * 
 * @param {number[]} ds 
 * @param {number} [d] 
 */
function updateDamages(ds, d) {
    if (d === undefined) {
        let n = ds.length
        if (n) {
            ds.push(ds[n - 1])
        } else {
            ds.push(0)
        }
    } else {
        ds.push(d)
    }
}

/**
 * 
 * @param {Object} bag 
 * @param {Artifact} A 
 */
function updateBag(bag, A) {
    if (bag[A.type].length == 0) {
        bag[A.type].push(A)
        return true
    } else if (bag[A.type][0].data.score < A.data.score) {
        bag[A.type][0] = A
        return true
    }
    return false
}

/**
 * 
 * @param {Object} bag 
 */
function bag2equip(bag) {
    let arts = []
    for (let key in bag) {
        if (bag[key].length) {
            arts.push(bag[key][0])
        }
    }
    return artifacts2equip(arts)
}

/**
 * 
 * @param {Stat} stat 
 * @param {Object} mainAffixes 
 * @param {number[]} weights
 * @param {number} N
 */
function simulateSingle(stat, mainAffixes, weights, N) {
    let bag = { flower: [], plume: [], sands: [], goblet: [], circlet: [] }
    let damages = [damage(stat)]
    for (let i = 0; i < N; ++i) {
        let type = choice(ArtifactTypes)
        let ma = mainAffixes[type]
        let p = MainAffixStat[type][ma]['p']
        if (Math.random() > p) {
            updateDamages(damages)
            continue
        }
        let A = randArtifact()
        A.type = type
        A.data.score = score(A, weights)
        if (!updateBag(bag, A)) {
            updateDamages(damages)
            continue
        }
        let e = bag2equip(bag)
        let s = stat.equip(e)
        let d = damage(s)
        updateDamages(damages, d)
    }
    return damages
}

/**
 * 
 * @param {Stat} stat 
 * @param {Object} mainAffixes 
 * @param {number[]} weights
 * @param {number} N number of artifacts
 * @param {number} T simulation times
 */
function simulate(stat, mainAffixes, weights, N, T) {
    let sims = []
    for (let i = 0; i < T; ++i) {
        let ds = simulateSingle(stat, mainAffixes, weights, N)
        sims.push(ds)
    }
    let clb = [], cub = [], avg = []
    for (let i = 0; i <= N; ++i) {
        let s1 = 0, s2 = 0
        for (let j = 0; j < T; ++j) {
            s1 += sims[j][i]
            s2 += sims[j][i] * sims[j][i]
        }
        let mu = s1 / T
        let delta = 1.96 * Math.sqrt((s2 - s1 * s1 / T) / (T * (T - 1)))
        clb.push(mu - delta)
        avg.push(mu)
        cub.push(mu + delta)
    }
    return { clb, avg, cub }
}

export { simulate, simulateSingle }